const items = $input.all();
const normalizePath = (value) => {
  const decoded = decodeURIComponent(String(value || ''));
  return decoded.startsWith('/') ? decoded : `/${decoded}`;
};
return items
  .filter((item) => item.json.type === 'file' && typeof item.json.path === 'string' && item.json.path.toLowerCase().endsWith('.md'))
  .map((item) => {
    const sourcePath = normalizePath(item.json.path);
    const fileName = sourcePath.split('/').pop();
    return {
      json: {
        source_path: sourcePath,
        file_name: fileName,
        archive_path: `/Notes/Blog Articles/4-Published/${fileName}`,
        manifest_path: '/Notes/Blog Articles/4-Published/json/blog-manifest.json'
      }
    };
  });

const sourcePath = $json.source_path;
const fileName = $json.file_name;
const archivePath = $json.archive_path;
const manifestPath = $json.manifest_path;
const buffer = await helpers.getBinaryDataBuffer(0, 'data');
const raw = buffer.toString('utf8');
const match = raw.match(/^---\n([\s\S]*?)\n---\n?([\s\S]*)$/);
const frontmatterRaw = match ? match[1] : '';
const body = (match ? match[2] : raw).trim();

const metadata = {};
let currentKey = null;
for (const line of frontmatterRaw.split(/\r?\n/)) {
  if (!line.trim()) continue;
  const listMatch = line.match(/^\s*-\s+(.*)$/);
  if (listMatch && currentKey) {
    if (!Array.isArray(metadata[currentKey])) metadata[currentKey] = [];
    metadata[currentKey].push(listMatch[1].trim().replace(/^['"]|['"]$/g, ''));
    continue;
  }
  const keyMatch = line.match(/^([A-Za-z0-9_]+):\s*(.*)$/);
  if (!keyMatch) continue;
  const [, key, rawValue] = keyMatch;
  currentKey = key;
  const value = rawValue.trim();
  if (value === '') {
    metadata[key] = [];
    continue;
  }
  if (value === 'null') {
    metadata[key] = null;
    continue;
  }
  metadata[key] = value.replace(/^['"]|['"]$/g, '');
}

const required = ['title', 'slug', 'excerpt', 'category'];
for (const field of required) {
  if (!metadata[field] || !String(metadata[field]).trim()) {
    throw new Error(`Missing required field: ${field}`);
  }
}
if (!body.trim()) {
  throw new Error('Reviewed markdown body is empty.');
}

const wordCount = body.split(/\s+/).filter(Boolean).length;
const readingTime = Math.max(1, Math.ceil(wordCount / 200));
const now = new Date().toISOString();
const publishedAt = metadata.publish_at && metadata.publish_at !== 'null' ? metadata.publish_at : now;
const slug = String(metadata.slug).trim();
const postPath = `/Notes/Blog Articles/4-Published/json/posts/${slug}.json`;

const post = {
  title: String(metadata.title),
  slug,
  excerpt: String(metadata.excerpt),
  category: String(metadata.category),
  tags: Array.isArray(metadata.tags) ? metadata.tags : [],
  published_at: publishedAt,
  updated_at: now,
  reading_time: readingTime,
  meta_description: String(metadata.meta_description || ''),
  body_markdown: body,
  source_note: sourcePath
};

const lines = [];
lines.push('---');
lines.push(`title: "${String(metadata.title).replace(/"/g, '\\"')}"`);
lines.push(`slug: "${slug.replace(/"/g, '\\"')}"`);
lines.push('status: published');
lines.push('tags:');
for (const tag of (Array.isArray(metadata.tags) ? metadata.tags : [])) lines.push(`  - ${String(tag)}`);
lines.push(`category: ${String(metadata.category)}`);
lines.push(`created_at: ${metadata.created_at || now}`);
lines.push(`updated_at: ${now}`);
lines.push(`source_type: ${metadata.source_type || 'note'}`);
lines.push(`source_path: "${String(metadata.source_path || '/Notes/Blog Articles/1-Review/').replace(/"/g, '\\"')}"`);
lines.push(`summary: "${String(metadata.summary || '').replace(/"/g, '\\"')}"`);
lines.push(`excerpt: "${String(metadata.excerpt).replace(/"/g, '\\"')}"`);
lines.push(`publish_at: ${publishedAt}`);
lines.push(`canonical_url: "${String(metadata.canonical_url || '').replace(/"/g, '\\"')}"`);
lines.push(`meta_description: "${String(metadata.meta_description || '').replace(/"/g, '\\"')}"`);
lines.push(`og_image: "${String(metadata.og_image || '').replace(/"/g, '\\"')}"`);
lines.push(`review_round: ${Number(metadata.review_round || 1) || 1}`);
lines.push(`published_json_path: "${postPath.replace(/"/g, '\\"')}"`);
lines.push('---');
lines.push('');
lines.push(body);

return {
  json: {
    source_path: sourcePath,
    archive_path: archivePath,
    manifest_path: manifestPath,
    post_path: postPath,
    published_markdown: lines.join('\n'),
    post_json: JSON.stringify(post, null, 2),
    manifest_entry: {
      title: post.title,
      slug: post.slug,
      excerpt: post.excerpt,
      category: post.category,
      tags: post.tags,
      published_at: post.published_at,
      updated_at: post.updated_at,
      reading_time: post.reading_time,
      meta_description: post.meta_description
    }
  }
};

const prior = $('Parse And Build Post').item.json;
let manifest = [];
if ($binary?.manifest?.data) {
  try {
    manifest = JSON.parse(Buffer.from($binary.manifest.data, 'base64').toString('utf8'));
  } catch (error) {
    manifest = [];
  }
}
if (!Array.isArray(manifest)) manifest = [];
const filtered = manifest.filter((entry) => entry.slug !== prior.manifest_entry.slug);
filtered.push(prior.manifest_entry);
filtered.sort((a, b) => new Date(b.published_at).getTime() - new Date(a.published_at).getTime());
return {
  json: {
    ...prior,
    manifest_json: JSON.stringify(filtered, null, 2)
  }
};

const source = $('Update Manifest JSON').item.json;
const payload = {
  slug: source.manifest_entry.slug,
  post_json: source.post_json,
  manifest_json: source.manifest_json
};

return {
  json: {
    ...source,
    repo_payload_b64: Buffer.from(JSON.stringify(payload), 'utf8').toString('base64')
  }
};
